<?php defined('ABSPATH') || exit; class FounderKit_License { private static ?FounderKit_License $instance=null; const OPTION_KEY='founderkit_license'; const API_URL='https://api.founderkit.com/validate'; const VALIDATION_INTERVAL=604800; public static function instance(): self { if(!self::$instance) self::$instance=new self(); return self::$instance; } public function __construct(){ add_action('founderkit_daily_license_check',[$this,'validate_remote']); } public static function defaults(): array { return ['license_key'=>'','activated'=>false,'status'=>'inactive','customer_email'=>'','customer_name'=>'','expiration_date'=>'','expiration_timestamp'=>0,'site_urls'=>[],'max_domains'=>0,'domains_active'=>0,'last_validation'=>0,'validation_interval'=>self::VALIDATION_INTERVAL,'api_validation_error'=>null,'addon_licenses'=>[]]; } public function all(): array { return wp_parse_args(get_option(self::OPTION_KEY,[]),self::defaults()); } public function get(string $key){ $all=$this->all(); return $all[$key]??null; } public function update(array $data): bool { return update_option(self::OPTION_KEY,array_merge($this->all(),$data)); } public function is_valid(): bool { $all=$this->all(); if(empty($all['license_key'])){ return false; } if(empty($all['activated'])){ return false; } if($all['status']!=='active'){ return false; } $expiration_timestamp=(int)$all['expiration_timestamp']; if($expiration_timestamp>0&&time()>$expiration_timestamp){ return false; } return true; } public function activate(string $license_key,array $validation_data): bool { $current_site_url=home_url(); $site_urls=$validation_data['site_urls']??[]; if(!in_array($current_site_url,$site_urls,true)){ $site_urls[]=$current_site_url; } return $this->update(['license_key'=>sanitize_key($license_key),'activated'=>true,'status'=>'active','customer_email'=>$validation_data['customer_email']??'','customer_name'=>$validation_data['customer_name']??'','expiration_date'=>$validation_data['expiration_date']??'','expiration_timestamp'=>$validation_data['expiration_timestamp']??0,'site_urls'=>$site_urls,'max_domains'=>(int)($validation_data['max_domains']??1),'domains_active'=>count($site_urls),'last_validation'=>time(),'api_validation_error'=>null]); } public function deactivate(): bool { return $this->update(self::defaults()); } public function validate_remote(): bool { $license_key=$this->get('license_key'); if(empty($license_key)){ return false; } $last_validation=(int)$this->get('last_validation'); $validation_interval=(int)$this->get('validation_interval'); if(time()<$last_validation+$validation_interval){ return true; } $response=wp_remote_post(self::API_URL,['body'=>['license_key'=>$license_key,'site_url'=>home_url(),'domain'=>$_SERVER['HTTP_HOST']?host():''],'timeout'=>10]); if(is_wp_error($response)){ $this->update(['api_validation_error'=>$response->get_error_message()]); return false; } $body=json_decode(wp_remote_retrieve_body($response),true); if($body['valid']??false){ $this->activate($license_key,$body); return true; }else{ $this->update(['status'=>'invalid','api_validation_error'=>$body['message']??'License validation failed']); return false; } } public function get_remaining_days(): int { $expiration_timestamp=(int)$this->get('expiration_timestamp'); if($expiration_timestamp<=0){ return 0; } $remaining=($expiration_timestamp-time())/DAY_IN_SECONDS; return max(0,(int)$remaining); } public function get_license_status(): array { $is_valid=$this->is_valid(); $remaining_days=$this->get_remaining_days(); return ['valid'=>$is_valid,'status'=>$this->get('status'),'expiration_date'=>$this->get('expiration_date'),'remaining_days'=>$remaining_days,'customer_name'=>$this->get('customer_name'),'customer_email'=>$this->get('customer_email'),'domains_active'=>$this->get('domains_active'),'max_domains'=>$this->get('max_domains'),'api_error'=>$this->get('api_validation_error')]; } }
